// --- Telegram MarkdownV2 Escaping Function ---
function escapeMarkdownV2(text) {
  const str = String(text || '');
  // Escape ALL MarkdownV2 reserved characters
  return str
    .replace(/\\/g, '\\\\')           // Backslash must be first
    .replace(/_/g, '\\_')             // Underscore
    .replace(/\*/g, '\\*')            // Asterisk
    .replace(/\[/g, '\\[')            // Opening square bracket
    .replace(/\]/g, '\\]')            // Closing square bracket
    .replace(/\(/g, '\\(')            // Opening parenthesis
    .replace(/\)/g, '\\)')            // Closing parenthesis
    .replace(/~/g, '\\~')             // Tilde
    .replace(/`/g, '\\`')             // Backtick
    .replace(/>/g, '\\>')             // Greater than
    .replace(/#/g, '\\#')             // Hash
    .replace(/\+/g, '\\+')            // Plus
    .replace(/-/g, '\\-')             // Hyphen/minus
    .replace(/=/g, '\\=')             // Equals
    .replace(/\|/g, '\\|')            // Pipe
    .replace(/\{/g, '\\{')            // Opening curly brace
    .replace(/\}/g, '\\}')            // Closing curly brace
    .replace(/\./g, '\\.')            // Period/dot
    .replace(/!/g, '\\!');            // Exclamation mark
}

// --- Resilient JSON Parse Function ---
function resilientJsonParse(jsonString) {
  if (!jsonString || typeof jsonString !== 'string') return null;

  try {
    // Remove trailing commas before } or ]
    const correctedJson = jsonString.replace(/,\s*([}\]])/g, '$1');
    return JSON.parse(correctedJson);
  } catch (e) {}

  try {
    // Try to extract the first {...} block
    const match = jsonString.match(/\{[\s\S]*\}/);
    if (match && match[0]) return JSON.parse(match[0]);
  } catch (e) {}

  return null;
}

