const item = items[0];
const llmOutput = item?.json?.output;

if (!llmOutput) {
  // Fallback for no output
  return [{
    json: {
      tool_calls: [{
        tool_name: 'answer_user',
        tool_input: {
          message: escapeMarkdownV2("I'm sorry, I seem to be having a little trouble. Please try again.")
        }
      }]
    }
  }];
}

// Remove code block markers (triple backticks, with or without language)
const cleanedStr = llmOutput.trim()
  .replace(/```[\w]*\n?/g, '')    // Remove opening code block with optional language
  .replace(/```/g, '');           // Remove closing code block

const parsedJson = resilientJsonParse(cleanedStr);

if (parsedJson && parsedJson.tool_calls && Array.isArray(parsedJson.tool_calls)) {
  // SUCCESS: Escape all message content in tool_calls before returning
  const escapedJson = {
    ...parsedJson,
    tool_calls: parsedJson.tool_calls.map(toolCall => {
      if (toolCall.tool_name === 'answer_user' && toolCall.tool_input && toolCall.tool_input.message) {
        return {
          ...toolCall,
          tool_input: {
            ...toolCall.tool_input,
            message: escapeMarkdownV2(toolCall.tool_input.message)
          }
        };
      }
      // For other tool types, escape any message fields we find
      if (toolCall.tool_input) {
        const escapedInput = { ...toolCall.tool_input };
        Object.keys(escapedInput).forEach(key => {
          if (typeof escapedInput[key] === 'string' && (key.includes('message') || key.includes('text') || key.includes('content'))) {
            escapedInput[key] = escapeMarkdownV2(escapedInput[key]);
          }
        });
        return {
          ...toolCall,
          tool_input: escapedInput
        };
      }
      return toolCall;
    })
  };

  return [{ json: escapedJson }];
} else {
  // FALLBACK: If parsing fails or the structure is wrong, send an error message.
  console.error("Failed to parse LLM output or find tool_calls array. Raw output:", llmOutput);
  return [{
    json: {
      tool_calls: [{
        tool_name: 'answer_user',
        tool_input: {
          message: escapeMarkdownV2("My apologies, I couldn't structure your request. Could you rephrase it?")
        }
      }]
    }
  }];
}

